import{_ as e,o as t,c as o,O as n}from"./chunks/framework.bdcb0ee1.js";const m=JSON.parse('{"title":"Section Management","description":"","frontmatter":{},"headers":[],"relativePath":"administration/structure/section-management.md","filePath":"administration/structure/section-management.md","lastUpdated":1773167115000}'),i={name:"administration/structure/section-management.md"},s=n('<h1 id="section-management" tabindex="-1">Section Management <a class="header-anchor" href="#section-management" aria-label="Permalink to &quot;Section Management&quot;">​</a></h1><p>ForumSpark gives you fine-grained control over your board structure by letting you create and manage individual sections. Sections can be either <strong>categories</strong> (containers) or <strong>forums</strong> (postable areas), depending on how you configure them.</p><h2 id="accessing-the-admin-panel" tabindex="-1">Accessing the Admin Panel <a class="header-anchor" href="#accessing-the-admin-panel" aria-label="Permalink to &quot;Accessing the Admin Panel&quot;">​</a></h2><p>To begin managing sections, access your Admin Control Panel through the User menu in the top-right navigation bar. Select <strong>&quot;Admin CP&quot;</strong> from the dropdown.</p><p>Once inside, look under the <strong>Forum Sections</strong> menu and click <strong>&quot;Create Sections&quot;</strong>.</p><h2 id="creating-a-new-section" tabindex="-1">Creating a New Section <a class="header-anchor" href="#creating-a-new-section" aria-label="Permalink to &quot;Creating a New Section&quot;">​</a></h2><p>When creating a new section, start by providing the basic information:</p><ul><li><strong>Location</strong>: Select where this section should appear in the forum hierarchy. You can create a top-level category or place this forum under an existing section.</li><li><strong>Name</strong>: The title of the section. This will be shown in the forum index.</li><li><strong>Description</strong>: A short summary explaining the section&#39;s purpose. BBCode is supported here.</li></ul><img width="1920" height="1691" alt="image" src="https://github.com/user-attachments/assets/7f7af879-383c-4ed4-a46a-f170e20e6ddd"><h2 id="posting-controls" tabindex="-1">Posting Controls <a class="header-anchor" href="#posting-controls" aria-label="Permalink to &quot;Posting Controls&quot;">​</a></h2><p>These options determine how users can interact with the section:</p><ul><li><strong>Allow posting</strong>: If disabled, the section becomes a container and cannot contain topics.</li><li><strong>Post count enabled</strong>: Determines whether posts in this section contribute to the user’s post count.</li><li><strong>Allow users to create polls</strong>: Enables poll creation inside topics.</li><li><strong>Enable best answer</strong>: Lets topic authors select a best answer, useful for Q&amp;A-style sections.</li><li><strong>Users can only see topics made by themselves</strong>: Useful for support areas or private submissions. Admins and moderators can still see all topics.</li></ul><h2 id="templates" tabindex="-1">Templates <a class="header-anchor" href="#templates" aria-label="Permalink to &quot;Templates&quot;">​</a></h2><p>You can select a <strong>template</strong> to be prefilled when users create a new topic in this section. This is helpful for guiding users in structured posts like bug reports, feedback, or applications.</p><h2 id="topic-sorting-redirection" tabindex="-1">Topic Sorting &amp; Redirection <a class="header-anchor" href="#topic-sorting-redirection" aria-label="Permalink to &quot;Topic Sorting &amp; Redirection&quot;">​</a></h2><ul><li><strong>Sort topics by</strong>: Choose the default topic order (e.g., latest reply time, creation date).</li><li><strong>Sort direction</strong>: Ascending or descending.</li><li><strong>Redirect forum</strong>: Turn this section into a redirect link to another URL.</li></ul><h2 id="forum-access" tabindex="-1">Forum Access <a class="header-anchor" href="#forum-access" aria-label="Permalink to &quot;Forum Access&quot;">​</a></h2><p>Permissions are assigned per user group for the following actions:</p><ul><li><strong>View</strong>: Whether users can see the section exists</li><li><strong>Read</strong>: Whether they can read individual topics</li><li><strong>Reply</strong>: Whether they can post replies</li><li><strong>Start</strong>: Whether they can start new topics</li></ul><p>These settings let you define public, private, or restricted-access sections depending on your needs.</p><h2 id="forum-moderators" tabindex="-1">Forum Moderators <a class="header-anchor" href="#forum-moderators" aria-label="Permalink to &quot;Forum Moderators&quot;">​</a></h2><p>You can assign moderators to a section by selecting one or more <strong>user groups</strong>. Any users within these groups will receive elevated privileges in this section, regardless of their global role.</p><p>At this time, <strong>individual users cannot be assigned as section moderators</strong> directly. This is an intentional design choice to keep moderation roles easier to manage and consistent at the group level.</p><h2 id="tips" tabindex="-1">Tips <a class="header-anchor" href="#tips" aria-label="Permalink to &quot;Tips&quot;">​</a></h2><ul><li>Use containers for grouping related forums without allowing posting.</li><li>Support-style sections often benefit from enabling the &quot;users can only see their own topics&quot; option.</li><li>You can update or reorganize sections at any time by editing them in the Section Manager.</li></ul>',25),r=[s];function a(c,l,h,d,g,u){return t(),o("div",null,r)}const f=e(i,[["render",a]]);export{m as __pageData,f as default};
